"""Stage 6 deployment: Portfolio Analytics Engine"""
import base64, os

FILES = {
    "/app/app/services/portfolio_analytics_service.py": """""",
    "/app/app/api/v1/routers/portfolio_analytics.py": """""",
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    data = base64.b64decode(b64)
    with open(path, "wb") as f:
        f.write(data)
    print(f"OK: {path} ({len(data)} bytes)")

# Patch main.py to include portfolio_analytics router
main_path = "/app/app/main.py"
with open(main_path, "r") as f:
    content = f.read()

if "portfolio_analytics" not in content:
    # Add import
    import_line = "from app.api.v1.routers import islamic_finance"
    new_import = import_line + "\nfrom app.api.v1.routers import portfolio_analytics"
    content = content.replace(import_line, new_import)
    
    # Add router include
    include_line = "app.include_router(islamic_finance.router, prefix=\"/api/v1\")"
    new_include = include_line + "\n\n# Stage 6: Portfolio Analytics Engine\napp.include_router(portfolio_analytics.router, prefix=\"/api/v1\")"
    content = content.replace(include_line, new_include)
    
    with open(main_path, "w") as f:
        f.write(content)
    print(f"OK: main.py patched with portfolio_analytics router")
else:
    print("SKIP: portfolio_analytics already in main.py")

print("\n=== Stage 6 backend deployment complete ===")
